// PNG mime type, base64-encoded payload
export const BRAND_LOGO_DATA_URI = "data:image/png;base64,";

let _brandLogoBuffer: Buffer | null | undefined;

/**
 * Returns the brand logo as a Node Buffer (cached after first call).
 * Returns null only if base64 decoding fails (should never happen).
 */
export function getBrandLogoBuffer(): Buffer | null {
  if (_brandLogoBuffer !== undefined) return _brandLogoBuffer;
  try {
    const b64 = BRAND_LOGO_DATA_URI.split(',')[1];
    _brandLogoBuffer = b64 ? Buffer.from(b64, 'base64') : null;
  } catch {
    _brandLogoBuffer = null;
  }
  return _brandLogoBuffer;
}

